+fn parse_graphml_edgedefault_value(value: &[u8]) -> Option<bool> {
+    let text = std::str::from_utf8(value).ok()?;
+    match text.trim().to_ascii_lowercase().as_str() {
+        "directed" => Some(true),
+        "undirected" => Some(false),
+        _ => None,
+    }
